import { useEffect, useState } from "react";

export function titleEffect(
  initial: string,
  updated: string,
  delay: number
) {
  const [text, setText] = useState(initial);

  useEffect(() => {
    const timer = setTimeout(() => {
      setText(updated);
    }, delay);

    return () => clearTimeout(timer);
  }, [updated, delay]);

  return text;
}