"use client";

import { titleEffect } from "@/lib/titleEffect";

type DelayedTitleProps = {
  initial: string;
  updated: string;
  delay: number;
};

export function TitleEffect({
  initial,
  updated,
  delay,
}: DelayedTitleProps) {
  const title = titleEffect(initial, updated, delay);

  return <h1>{title}</h1>;
}